import java.util.Collections;
import java.util.IdentityHashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.QueryModelNode;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor;

/**
 * Winner-local planned annotations for the part of an expression template that is owned by that expression. Selected
 * child subtrees carry their own snapshots, so this structure stays proportional to the selected memo DAG instead of
 * retaining a cloned algebra tree for every winner.
 */
final class SelectedPlanMetrics {
	private final int localNodeCount;
	private final List<NodeMetrics> nodeMetrics;
	private final Map<String, Double> lateRootDoubleMetrics = new LinkedHashMap<>();

	private SelectedPlanMetrics(int localNodeCount, List<NodeMetrics> nodeMetrics) {
		this.localNodeCount = localNodeCount;
		this.nodeMetrics = nodeMetrics == null || nodeMetrics.isEmpty() ? List.of() : List.copyOf(nodeMetrics);
	}

	static SelectedPlanMetrics capture(TupleExpr template, PlanProvenance provenance) {
		List<QueryModelNode> nodes = localNodes(template);
		if (nodes.isEmpty()) {
			return new SelectedPlanMetrics(0, List.of());
		}
		EstimateSnapshot estimate = provenance == null ? null : provenance.estimate();
		Map<String, String> rootEstimateStrings = estimate == null ? Map.of() : estimate.stringMetrics();
		Map<String, Double> rootEstimateDoubles = estimate == null ? Map.of() : estimate.doubleMetrics();
		List<NodeMetrics> snapshots = new ArrayList<>();
		for (int index = 0; index < nodes.size(); index++) {
			QueryModelNode node = nodes.get(index);
			Map<String, String> strings = index == 0
					? copyDifference(node.getStringMetricsPlanned(), rootEstimateStrings)
					: immutableCopy(node.getStringMetricsPlanned());
			Map<String, Double> doubles = index == 0
					? copyDifference(node.getDoubleMetricsPlanned(), rootEstimateDoubles)
					: immutableCopy(node.getDoubleMetricsPlanned());
			Map<String, Long> longs = immutableCopy(node.getLongMetricsPlanned());
			double resultSize = index == 0 ? Double.NaN : finiteMetric(node.getResultSizeEstimate());
			double costEstimate = index == 0 ? Double.NaN : finiteMetric(node.getCostEstimate());
			if (!strings.isEmpty() || !doubles.isEmpty() || !longs.isEmpty()
					|| Double.isFinite(resultSize) || Double.isFinite(costEstimate)) {
				snapshots.add(new NodeMetrics(index, strings, doubles, longs, resultSize, costEstimate));
			}
		}
		return new SelectedPlanMetrics(nodes.size(), snapshots);
	}

	void apply(TupleExpr materializedPlan, PlanProvenance provenance) {
		List<QueryModelNode> nodes = localNodes(materializedPlan);
		if (nodes.size() != localNodeCount) {
			throw new IllegalStateException("Selected plan annotation shape changed: expected=" + localNodeCount
					+ ", actual=" + nodes.size());
		}
		for (QueryModelNode node : nodes) {
			clear(node.getStringMetricsPlanned());
			clear(node.getDoubleMetricsPlanned());
			clear(node.getLongMetricsPlanned());
		}
		if (!nodes.isEmpty() && provenance != null) {
			QueryModelNode root = nodes.getFirst();
			EstimateSnapshot estimate = provenance.estimate();
			applyStrings(root, estimate.stringMetrics());
			applyDoubles(root, estimate.doubleMetrics());
			CostVector cost = provenance.cost();
			if (Double.isFinite(cost.rows()) && cost.rows() >= 0.0d) {
				root.setResultSizeEstimate(cost.rows());
			}
			if (Double.isFinite(cost.workRows()) && cost.workRows() >= 0.0d) {
				root.setCostEstimate(cost.workRows());
			}
		}
		for (NodeMetrics snapshot : nodeMetrics) {
			QueryModelNode node = nodes.get(snapshot.nodeIndex());
			applyStrings(node, snapshot.stringMetrics());
			applyDoubles(node, snapshot.doubleMetrics());
			for (Map.Entry<String, Long> entry : snapshot.longMetrics().entrySet()) {
				node.setLongMetricPlanned(entry.getKey(), entry.getValue());
			}
			if (Double.isFinite(snapshot.resultSizeEstimate())) {
				node.setResultSizeEstimate(snapshot.resultSizeEstimate());
			}
			if (Double.isFinite(snapshot.costEstimate())) {
				node.setCostEstimate(snapshot.costEstimate());
			}
		}
		if (!nodes.isEmpty()) {
			applyDoubles(nodes.getFirst(), lateRootDoubleMetrics);
		}
	}

	void recordRootDoubleMetric(String name, double value) {
		if (name != null) {
			lateRootDoubleMetrics.put(name, value);
		}
	}

	private static List<QueryModelNode> localNodes(TupleExpr tupleExpr) {
		if (tupleExpr == null) {
			return List.of();
		}
		Set<QueryModelNode> selectedChildRoots = Collections.newSetFromMap(new IdentityHashMap<>());
		MemoInputLayout.slots(tupleExpr)
				.stream()
				.filter(slot -> slot.use() == MemoInput.Use.EXECUTABLE)
				.map(MemoInputLayout.Slot::input)
				.forEach(selectedChildRoots::add);
		List<QueryModelNode> result = new ArrayList<>();
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				if (selectedChildRoots.contains(node)) {
					return;
				}
				result.add(node);
				node.visitChildren(this);
			}
		});
		return result;
	}

	private static void applyStrings(QueryModelNode node, Map<String, String> metrics) {
		for (Map.Entry<String, String> entry : metrics.entrySet()) {
			node.setStringMetricPlanned(entry.getKey(), entry.getValue());
		}
	}

	private static void applyDoubles(QueryModelNode node, Map<String, Double> metrics) {
		for (Map.Entry<String, Double> entry : metrics.entrySet()) {
			node.setDoubleMetricPlanned(entry.getKey(), entry.getValue());
		}
	}

	private static void clear(Map<?, ?> metrics) {
		if (metrics.isEmpty()) {
			return;
		}
		try {
			metrics.clear();
		} catch (UnsupportedOperationException ignored) {
			// QueryModelNode permits immutable no-op metric maps.
		}
	}

	private static double finiteMetric(double value) {
		return Double.isFinite(value) && value >= 0.0d ? value : Double.NaN;
	}

	private static <K, V> Map<K, V> copyDifference(Map<K, V> source, Map<K, V> base) {
		if (source == null || source.isEmpty()) {
			return Map.of();
		}
		Map<K, V> difference = new LinkedHashMap<>();
		for (Map.Entry<K, V> entry : source.entrySet()) {
			if (!Objects.equals(entry.getValue(), base.get(entry.getKey()))) {
				difference.put(entry.getKey(), entry.getValue());
			}
		}
		return difference.isEmpty() ? Map.of() : Map.copyOf(difference);
	}

	private static <K, V> Map<K, V> immutableCopy(Map<K, V> source) {
		return source == null || source.isEmpty() ? Map.of() : Map.copyOf(source);
	}

	private record NodeMetrics(int nodeIndex, Map<String, String> stringMetrics,
			Map<String, Double> doubleMetrics, Map<String, Long> longMetrics, double resultSizeEstimate,
			double costEstimate) {
	}
}
